import{_ as a,o as e,c as n,a as i}from"./chunks/framework.BHSVNLI7.js";const u=JSON.parse('{"title":"调度器演进（四）：EEVDF——从虚拟公平到虚拟截止时间","description":"","frontmatter":{"title":"调度器演进（四）：EEVDF——从虚拟公平到虚拟截止时间","slug":"sched-evolution-eevdf","type":"supplementary","supplementary_for":[{"node_id":"sched-cfs","relation":"CFS 的终结者和替代者——从 vruntime 到 virtual deadline"},{"node_id":"sched-rt","relation":"实时调度的公平性维度——延迟与吞吐的分离"}],"difficulty":"advanced","tags":["scheduler","evolution","eevdf","cfs","virtual-deadline","latency"],"kernel_versions":["6.6","6.7","6.19","7.0","7.1"],"milestones":[{"version":"6.6","event":"EEVDF 替代 CFS 成为默认调度策略","commit":"5e963f2bd4654a202a8a05aa3a86cb0300b10e6c"},{"year":"2023-03","event":"Peter Zijlstra 发布 EEVDF 补丁集","reference":"https://lkml.org/lkml/2023/3/6/732"}]},"headers":[],"relativePath":"tutorials/kernel/sched/sched-evolution-04-eevdf.md","filePath":"tutorials/kernel/sched/sched-evolution-04-eevdf.md","lastUpdated":null}'),t={name:"tutorials/kernel/sched/sched-evolution-04-eevdf.md"};function l(r,s,p,d,c,h){return e(),n("div",null,[...s[0]||(s[0]=[i(`<h1 id="调度器演进-四-eevdf——从虚拟公平到虚拟截止时间" tabindex="-1">调度器演进（四）：EEVDF——从虚拟公平到虚拟截止时间 <a class="header-anchor" href="#调度器演进-四-eevdf——从虚拟公平到虚拟截止时间" aria-label="Permalink to &quot;调度器演进（四）：EEVDF——从虚拟公平到虚拟截止时间&quot;">​</a></h1><p>CFS 跑了 16 年。从 2007 年的 v2.6.23 到 2023 年的 v6.5，红黑树 + vruntime 的组合经受住了从手机到数据中心的考验。16 年里内核开发者给 CFS 打了无数补丁——group scheduling、bandwidth throttle、PELT 负载跟踪——但核心的选任务逻辑一直是&quot;找 vruntime 最小的那个&quot;。</p><p>2023 年，Peter Zijlstra——就是 2007 年帮 CFS 做&quot;自适应调度粒度和数学优化&quot;的那位——决定砍掉这棵红黑树的核心逻辑，换成一套基于虚拟截止时间的新算法。这个算法叫 EEVDF (Earliest Eligible Virtual Deadline First)，它不是凭空发明的，而是来自一篇 1995 年的学术论文。</p><h2 id="cfs-的根本缺陷-一个旋钮管两件事" tabindex="-1">CFS 的根本缺陷：一个旋钮管两件事 <a class="header-anchor" href="#cfs-的根本缺陷-一个旋钮管两件事" aria-label="Permalink to &quot;CFS 的根本缺陷：一个旋钮管两件事&quot;">​</a></h2><p>CFS 运行了 16 年，期间社区积累了大量的痛点。但最根本的问题只有一个：<strong>nice 值只能控制 CPU 时间份额，不能控制延迟。</strong></p><p>举个例子：一个音频处理进程和一个视频编码进程，可能需要相同份额的 CPU 时间（相同的 nice 值），但音频进程需要更低的延迟——它不需要更多 CPU 时间，只是需要被调度的频率更高、每次运行的时间更短。在 CFS 里，你没法表达&quot;给我同样多的 CPU，但要更频繁地给我&quot;这个需求。唯一的办法是调低 nice 值给它更多 CPU，但这改变了公平性。</p><p>Peter Zijlstra 在 LWN 的采访中说得很直白：</p><blockquote><p>&quot;如果我们能做到这一点，我们就可以删除一大堆糟糕的启发式代码。&quot;</p></blockquote><blockquote><p>&quot;它完全重构了基础调度器、放置、抢占、选择——一切。它们唯一共同点是它们都是基于虚拟时间的调度器。&quot;</p></blockquote><p>引用来源：LWN EEVDF 专题 (<a href="https://lwn.net/Articles/925371/" target="_blank" rel="noreferrer">https://lwn.net/Articles/925371/</a>)</p><h2 id="_1995-年的论文" tabindex="-1">1995 年的论文 <a class="header-anchor" href="#_1995-年的论文" aria-label="Permalink to &quot;1995 年的论文&quot;">​</a></h2><p>EEVDF 算法出自 1995 年（有时被引用为 1996 年）的一篇学术论文，标题是 &quot;Earliest Eligible Virtual Deadline First: A Flexible and Accurate Mechanism for Proportional Share Resource Allocation&quot;，作者是 Ion Stoica 和 Hussein Abdel-Wahab，来自 Old Dominion University 计算机科学系。</p><p>引用来源：ACM Digital Library (<a href="https://dl.acm.org/doi/10.5555/890606" target="_blank" rel="noreferrer">https://dl.acm.org/doi/10.5555/890606</a>)</p><p>核心公式非常简洁：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>vd_i = ve_i + r_i / w_i</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>其中 <code>vd_i</code> 是任务 i 的虚拟截止时间 (virtual deadline)，<code>ve_i</code> 是虚拟到达时间，<code>r_i</code> 是请求的时间片长度，<code>w_i</code> 是权重。调度时选择<strong>虚拟截止时间最早</strong>的<strong>合格</strong>任务——&quot;合格&quot;意味着任务的虚拟时间不超前于系统的虚拟时间。</p><p>这个公式的妙处在于：<code>r_i</code>（时间片长度）和 <code>w_i</code>（权重）是独立的旋钮。想要更低延迟？缩短 <code>r_i</code>，截止时间就更早，被调度得更频繁，但总 CPU 份额由 <code>w_i</code> 单独控制，不会变。</p><h2 id="commit-5e963f2bd465-大扫除" tabindex="-1">Commit 5e963f2bd465：大扫除 <a class="header-anchor" href="#commit-5e963f2bd465-大扫除" aria-label="Permalink to &quot;Commit 5e963f2bd465：大扫除&quot;">​</a></h2><p>Peter Zijlstra 的 EEVDF 合入 commit 做了大量删除。我们看这个 commit 实际做了什么。</p><h3 id="删除全局延迟参数" tabindex="-1">删除全局延迟参数 <a class="header-anchor" href="#删除全局延迟参数" aria-label="Permalink to &quot;删除全局延迟参数&quot;">​</a></h3><div class="language-diff vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">diff</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">// kernel/sched/fair.c — 移除 CFS 的全局调优参数</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-unsigned int sysctl_sched_latency			= 6000000ULL;</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-static unsigned int normalized_sysctl_sched_latency	= 6000000ULL;</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-unsigned int sysctl_sched_idle_min_granularity		= 750000ULL;</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-unsigned int sysctl_sched_wakeup_granularity		= 1000000UL;</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-static unsigned int normalized_sysctl_sched_wakeup_granularity	= 1000000UL;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>CFS 的 <code>sched_latency</code>（默认 6ms 的目标延迟）和 <code>wakeup_granularity</code>（唤醒抢占粒度）全部删除。这些是 CFS 最难调的参数——它们控制&quot;多长时间内所有任务都应该至少跑一次&quot;和&quot;唤醒时允许抢占的最小粒度&quot;，但不同负载下最佳值完全不同。EEVDF 不需要它们了，因为虚拟截止时间自然地解决了延迟问题。</p><h3 id="删除-buddy-系统" tabindex="-1">删除 buddy 系统 <a class="header-anchor" href="#删除-buddy-系统" aria-label="Permalink to &quot;删除 buddy 系统&quot;">​</a></h3><div class="language-diff vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">diff</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">// include/linux/sched.h — 从 cfs_rq 移除 buddy 指针</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> struct cfs_rq {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 	struct sched_entity	*curr;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 	struct sched_entity	*next;</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-	struct sched_entity	*last;   // ← 删除</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-	struct sched_entity	*skip;   // ← 删除</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><div class="language-diff vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">diff</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">// kernel/sched/fair.c — 移除 buddy 管理函数</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-static void __clear_buddies_last(struct sched_entity *se) { ... }</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-static void __clear_buddies_skip(struct sched_entity *se) { ... }</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-static void set_last_buddy(struct sched_entity *se) { ... }</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-static void set_skip_buddy(struct sched_entity *se) { ... }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>CFS 的 buddy 系统有三类：<code>next</code> buddy 是唤醒时的首选，<code>last</code> buddy 是 cache 热度偏好，<code>skip</code> buddy 是 yield 时跳过。这又是一套启发式——&quot;刚唤醒的任务可能和当前任务有 cache 亲和性所以优先选它&quot;之类的猜测。EEVDF 的虚拟截止时间使得这些优化不再必要。</p><h3 id="删除时间片计算" tabindex="-1">删除时间片计算 <a class="header-anchor" href="#删除时间片计算" aria-label="Permalink to &quot;删除时间片计算&quot;">​</a></h3><div class="language-diff vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">diff</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">// kernel/sched/fair.c — 移除 CFS 的按权重比例时间片计算</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-static u64 __sched_period(unsigned long nr_running)</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-{</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-	if (unlikely(nr_running &gt; sched_nr_latency))</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-		return nr_running * sysctl_sched_min_granularity;</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-	else</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-		return sysctl_sched_latency;</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-}</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-static u64 sched_slice(struct cfs_rq *cfs_rq, struct sched_entity *se)</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-{</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-	// ... 40 行按权重比例计算 ...</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>CFS 的 <code>sched_slice()</code> 按 &quot;period × weight / total_weight&quot; 计算每个任务该跑多久。EEVDF 简化为基础粒度 + 虚拟截止时间：</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// kernel/sched/fair.c:1029 (v6.6) — EEVDF 的新方案</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">se</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">slice </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> sysctl_sched_base_slice;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 固定基础粒度</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">se</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">deadline </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> se</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">vruntime </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> calc_delta_fair</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(se</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">slice</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, se);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 虚拟截止时间</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>不再按权重比例算时间片，而是给每个任务一个固定的基础粒度，然后根据权重计算对应的虚拟截止时间。权重高的任务截止时间更早（因为 <code>r_i / w_i</code> 更小），自然被调度得更频繁，但每次运行的时间一样长。</p><h3 id="简化选任务" tabindex="-1">简化选任务 <a class="header-anchor" href="#简化选任务" aria-label="Permalink to &quot;简化选任务&quot;">​</a></h3><div class="language-diff vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">diff</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">// kernel/sched/fair.c — 旧版（CFS + EEVDF feature flag 共存时期）</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-static struct sched_entity *</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-pick_next_entity(struct cfs_rq *cfs_rq, struct sched_entity *curr)</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-{</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-	if (sched_feat(EEVDF)) {</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-		// ... EEVDF 路径 ...</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-		return pick_eevdf(cfs_rq);</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-	}</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-	// ... 大量 buddy 选择逻辑 ...</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">// 新版（EEVDF only）</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">+static struct sched_entity *</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">+pick_next_entity(struct cfs_rq *cfs_rq, struct sched_entity *curr)</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">+{</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">+	if (sched_feat(NEXT_BUDDY) &amp;&amp;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">+	    cfs_rq-&gt;next &amp;&amp; entity_eligible(cfs_rq, cfs_rq-&gt;next))</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">+		return cfs_rq-&gt;next;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">+</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">+	return pick_eevdf(cfs_rq);  // ← 直接调用 EEVDF</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">+}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br></div></div><p><code>pick_eevdf()</code> 的逻辑：找到<strong>虚拟时间不超过当前虚拟时间</strong>（合格）且<strong>虚拟截止时间最早</strong>的任务。这是一个数学上可证明公平的选择策略，不需要任何启发式。</p><h3 id="删除-sched-features" tabindex="-1">删除 sched features <a class="header-anchor" href="#删除-sched-features" aria-label="Permalink to &quot;删除 sched features&quot;">​</a></h3><div class="language-diff vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">diff</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">// kernel/sched/features.h</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-SCHED_FEAT(LAST_BUDDY, true)     // 删除</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-SCHED_FEAT(ALT_PERIOD, true)     // 删除</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-SCHED_FEAT(BASE_SLICE, true)     // 删除</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-SCHED_FEAT(EEVDF, true)          // 删除 — 不再是可选 feature，是唯一实现</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>最后一个特别有意思：<code>EEVDF</code> 本身曾经是一个可选的 <code>sched_feature</code>，可以通过 <code>sysctl</code> 关掉退回 CFS。但这个 commit 把它删了——EEVDF 不再是实验性的可选功能，而是<strong>唯一的实现</strong>。</p><h2 id="v6-6-之后的持续演进" tabindex="-1">v6.6 之后的持续演进 <a class="header-anchor" href="#v6-6-之后的持续演进" aria-label="Permalink to &quot;v6.6 之后的持续演进&quot;">​</a></h2><p>EEVDF 合入后并没有停止变化。从 v6.6 到 v7.1-rc，调度器经历了密集的修复和优化：</p><p>在 v6.7 到 v6.19 之间，主要做了 lag clamp（限制任务的 lag 值防止极端情况）、zero_vruntime（fork 时新任务的 vruntime 初始化）和 avg_vruntime（队列的平均 vruntime 计算）等修复。v7.0 做了一次 vruntime 算术重做，把 wrapped-signed 问题清理干净，同时简化了抢占模式——现代架构（x86_64、ARM64、RISC-V）上只保留 fully preemptible 和 lazy 两种模式，去掉了 no-preempt 和 voluntary 选项。v7.0 还引入了基于 RSEQ 的时间片扩展机制，让用户空间进程可以请求临时延长 CPU 时间以完成临界区操作。v7.1-rc 引入了 <code>rel_deadline</code> 处理 fork 时的 deadline 继承问题，以及 delayed dequeue 修复。</p><p>这些后续变化说明 EEVDF 的合入只是一个开始——新算法暴露了 CFS 时代被掩盖的边界条件，清理这些边界条件花了好几个版本。但核心的&quot;虚拟截止时间&quot;选任务逻辑从 v6.6 到 v7.1 一直没变。</p><h2 id="回头看-公平性的第二次进化" tabindex="-1">回头看：公平性的第二次进化 <a class="header-anchor" href="#回头看-公平性的第二次进化" aria-label="Permalink to &quot;回头看：公平性的第二次进化&quot;">​</a></h2><p>如果我们把视野拉长到整个调度器历史，会发现一个清晰的演进脉络：</p><p>O(1) 时代是<strong>优先级驱动 + 启发式</strong>，用 <code>sleep_avg</code> 猜谁是交互型任务，给优先级奖励。CFS 时代是<strong>公平驱动 + 单旋钮</strong>，用 vruntime 保证 CPU 时间份额的公平，但延迟和吞吐共享一个 nice 值旋钮。EEVDF 时代是<strong>公平驱动 + 双旋钮</strong>，用虚拟截止时间把延迟和 CPU 份额解耦，不再需要启发式。</p><p>每一代都解决了上一代的核心痛点，同时暴露出新的问题。EEVDF 的&quot;新问题&quot;是什么？现在下定论还太早——它才运行了不到三年。但从 v7.0 和 v7.1 的变化密度来看，EEVDF 的边界条件比 CFS 复杂，可能需要更长时间才能完全稳定。</p><hr><h2 id="时间线" tabindex="-1">时间线 <a class="header-anchor" href="#时间线" aria-label="Permalink to &quot;时间线&quot;">​</a></h2><table tabindex="0"><thead><tr><th>时间</th><th>事件</th></tr></thead><tbody><tr><td>1995</td><td>Stoica &amp; Abdel-Wahab 发表 EEVDF 论文</td></tr><tr><td>2023-03</td><td>Peter Zijlstra 发布 EEVDF 补丁集到 LKML</td></tr><tr><td>2023-05-31</td><td>Commit <code>5e963f2bd465</code> — &quot;sched/fair: Commit to EEVDF&quot;</td></tr><tr><td>2023-10 (6.6)</td><td>EEVDF 替代 CFS 成为默认调度策略</td></tr><tr><td>2023-10 ~ 2025 (6.7-6.19)</td><td>持续修复：lag clamp, zero_vruntime, avg_vruntime</td></tr><tr><td>2026-04 (7.0)</td><td>vruntime 算术重做，抢占模式简化，RSEQ 时间片扩展</td></tr><tr><td>2026-05 (7.1-rc)</td><td>rel_deadline, delayed dequeue 修复</td></tr></tbody></table><h2 id="参考文献" tabindex="-1">参考文献 <a class="header-anchor" href="#参考文献" aria-label="Permalink to &quot;参考文献&quot;">​</a></h2><ul><li>Commit <code>5e963f2bd465</code> (2023-05-31, Peter Zijlstra, &quot;sched/fair: Commit to EEVDF&quot;): <code>git show 5e963f2bd465</code> — 本地 <code>third_party/linux</code>，包含于 <code>v6.6-rc1</code></li><li>LWN: EEVDF 专题 (2023): <a href="https://lwn.net/Articles/925371/" target="_blank" rel="noreferrer">https://lwn.net/Articles/925371/</a></li><li>Kernel 文档: <a href="https://docs.kernel.org/scheduler/sched-eevdf.html" target="_blank" rel="noreferrer">https://docs.kernel.org/scheduler/sched-eevdf.html</a></li><li>Kernel Internals: <a href="https://kernel-internals.org/sched/eevdf/" target="_blank" rel="noreferrer">https://kernel-internals.org/sched/eevdf/</a></li><li>LKML: EEVDF 补丁 (2023-03-06): <a href="https://lkml.org/lkml/2023/3/6/732" target="_blank" rel="noreferrer">https://lkml.org/lkml/2023/3/6/732</a></li><li>学术论文: <a href="https://dl.acm.org/doi/10.5555/890606" target="_blank" rel="noreferrer">https://dl.acm.org/doi/10.5555/890606</a></li><li>Phoronix: Linux 7.0 调度器变化: <a href="https://www.phoronix.com/news/Linux-7.0-Scheduler" target="_blank" rel="noreferrer">https://www.phoronix.com/news/Linux-7.0-Scheduler</a></li><li>Phoronix: Linux 7.1 调度器变化: <a href="https://www.phoronix.com/news/Linux-7.1-Scheduler" target="_blank" rel="noreferrer">https://www.phoronix.com/news/Linux-7.1-Scheduler</a></li></ul>`,50)])])}const k=a(t,[["render",l]]);export{u as __pageData,k as default};
